// ============================================================
// Experience.jsx
// Vertical timeline of academic and project experience.
// Leaf-shaped bullets animate on hover.
// ============================================================

import React, { useEffect, useRef } from 'react';
import '../styles/sections.css';

// ── Experience data ───────────────────────────────────────────
const EXPERIENCE = [
  {
    period: '2024 – Present',
    role: 'Web Developer',
    org: 'Superposition Toronto',
    description:
      'Monitored website performance and resolved 15+ technical or content issues, ensuring consistent functionality, accessibility, and up-to-date information for the organization’s community and events.',
  },
  {
    period: '2022 - 2026',
    role: 'Lead Programmer',
    org: 'Tech Under Twenty',
    description:
      'Built a complete browser-based adventure game from scratch using p5.js. Implemented game loop architecture, collision detection, procedural obstacle generation, and score tracking.',
  },
  {
    period: '2023 – Present',
    role: 'Student · Computer Science',
    org: 'High School',
    description:
      'Pursuing advanced courses in computer science and mathematics, with a focus on software development, algorithms, and data structures. Active in school tech and entrepreneurship clubs.',
  },
  {
    period: '2022 – Present',
    role: 'Independent Learner',
    org: 'Web Development',
    description:
      'Self-taught HTML, CSS, JavaScript, and React through online resources, personal projects, and open-source contributions. Continuously expanding my toolkit with new libraries and tools.',
  },
];

// Scroll-reveal hook
const useReveal = (threshold = 0.1) => {
  const ref = useRef(null);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const observer = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) { el.classList.add('exp-vis'); observer.disconnect(); } },
      { threshold }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, [threshold]);
  return ref;
};

// ── Experience section ────────────────────────────────────────
const Experience = () => {
  const headRef = useReveal();

  return (
    <section id="experience" className="experience section">
      <div className="container">
        {/* Heading */}
        <div
          ref={headRef}
          className="exp-reveal"
          style={{
            opacity: 0, transform: 'translateY(24px)',
            transition: 'opacity 0.6s ease, transform 0.6s ease',
          }}
        >
          <span className="section-label">Journey</span>
          <h2 className="section-title">Experience &<br /><em style={{ fontStyle: 'italic' }}>Growth</em></h2>
        </div>

        {/* Timeline */}
        <div className="experience__timeline">
          {EXPERIENCE.map((item, i) => {
            // Each item gets its own ref for staggered reveal
            // eslint-disable-next-line react-hooks/rules-of-hooks
            const itemRef = useReveal(0.1);
            return (
              <div
                key={i}
                ref={itemRef}
                className="experience__item exp-reveal"
                style={{
                  opacity: 0,
                  transform: 'translateX(-20px)',
                  transition: `opacity 0.6s ease ${0.1 + i * 0.12}s, transform 0.6s ease ${0.1 + i * 0.12}s`,
                }}
              >
                {/* Leaf-shaped bullet */}
                <div className="experience__dot" aria-hidden="true" />

                <p className="experience__period">{item.period}</p>
                <h3 className="experience__role">{item.role}</h3>
                <p className="experience__org">{item.org}</p>
                <p className="experience__desc">{item.description}</p>
              </div>
            );
          })}
        </div>
      </div>

      <style>{`
        .exp-reveal.exp-vis {
          opacity: 1 !important;
          transform: translate(0) !important;
        }
      `}</style>
    </section>
  );
};

export default Experience;
